import setup, { type Debugger } from 'debug'

const debug = setup('fs')
const verbose = setup('fsverbose')

// Check for localStorage (which is null in some Android WebViews) to prevent
// crashing pages that are embedded in the mobile app.
const hasLocalStorage = typeof localStorage !== 'undefined' && localStorage !== null

type DebugFunction = ((...args: Parameters<Debugger>) => void) & Partial<Debugger>

// If localStorage is not available, debugging can’t be enabled, so a no-op is fine
const noOp: DebugFunction = () => undefined

export default function zionDebug(namespace: string): DebugFunction {
  if (!namespace) throw new Error('No namespace defined.')
  if (!hasLocalStorage) return noOp

  return debug.extend(namespace)
}

export function debugVerbose(namespace: string): DebugFunction {
  if (!namespace) throw new Error('No namespace defined.')
  if (!hasLocalStorage) return noOp

  return verbose.extend(namespace)
}

/**
 * A function which is 'smart' enough to not fail jest unit tests when logging a deprecation warning
 *
 * @param args - all arguments will be passed directly to console.warnNoMask or console.warn
 */
export function printDeprecationWarning(...args: Parameters<Console['warn']>): void {
  /* eslint-disable-next-line no-console -- the whole purpose of this function is to log using console */
  const printWarning = console.warnNoMask || console.warn

  printWarning(...args)
}

export { setup as debugConfig }
