export const availableLangs = langText

const hasWindow = typeof window !== 'undefined'

// console.log('isInit', i18n.isInitializedFrontier, i18n.language, i18n)
if (!i18n.isInitializedFrontier) {
  logVerbose.enabled && console.trace('setting up i18next ...')
  _initializeI18nInstance(i18n, appLocales)
  i18n.isInitializedFrontier = true

  logVerbose('i18n is set up', i18n)
} else {
  logVerbose.enabled && console.trace('i18n already initialized, skipping ...')
}

// eslint-disable-next-line no-underscore-dangle -- this is a private function not to be used anywhere else; it is for use in tests where we need the configuration updated with new settings
function _initializeI18nInstance(i18nInstance, locales = appLocales) {
  logVerbose('_initializeI18nInstance called', i18nInstance.language, i18nInstance.isInitializedFrontier, locales)
  if (!i18nInstance.isInitializedFrontier) {
    i18nInstance.on('languageChanged', (lng) => {
      logVerbose('languageChanged called', lng, i18n.language, i18n.isLanguageChangingTo)
      // locale = i18n.language
      updateLocale(lng)
      updateFormatLocale(lng)
      log('languageChanged updated language and setting for other libraries:', lng, i18n.language)
    })
  }
  let cookieDomain
  if (hasWindow) {
    cookieDomain = window.location.hostname.includes('.familysearch.org')
      ? '.familysearch.org'
      : window.location.hostname
  }

  const languageDetector = new LanguageDetector()
  // this custom detector will be needed as long as the URL differs from the internal code, for example `zh-Hant` in the URL vs `zh` in i18n.language
  languageDetector.addDetector({
    name: 'fsZhHant',
    lookup() {
      if (typeof window === 'undefined') return undefined
      logVerbose('fsZhHant detector lookup called', window?.location?.toString())
      const url = new URL(window.location)
      return url.pathname.startsWith('/zh-Hant') || url.searchParams.get('lang') === 'zh-Hant' ? 'zh' : undefined
    },
  })

  const instanceSetup = i18nInstance
    .use(languageDetector)
    .use(
      new ICU({
        formats: {
          number: {
            integer: {
              maximumFractionDigits: 0,
            },
          },
        },
      })
    )
    .use(
      new Pseudo({
        languageToPseudo: 'eo',
      })
    )
    .use(initReactI18next)

  if (typeof jest === 'undefined') {
    instanceSetup.use(chainBackends)
  }

  return instanceSetup.init({
    // since we load translations async, this waits until the backend resources are loaded before actually initializing.
    // English is loaded async, but bundled. All other languages are downloaded via webpack async.
    initImmediate: false,
    fallbackLng: {
      'zh-hans': ['zh', 'en'],
      'zh-Hans': ['zh-hans', 'zh', 'en'],
      'zh-hant': ['zh', 'en'],
      'zh-Hant': ['zh-hant', 'zh', 'en'],
      nb: ['no', 'en'],
      nn: ['no', 'en'],
      ca: ['es', 'en'],
      bs: ['hr', 'en'],
      default: ['en'],
    },
    lowerCaseLng: true,
    interpolation: { escapeValue: false, format: formatValue },
    detection: {
      order: ['fsZhHant', 'querystring', 'path', 'cookie', 'htmlTag', 'navigator'],
      lookupQuerystring: 'lang',
      lookupCookie: 'fslanguage',
      lookupFromPathIndex: 0,
      caches: [],
      excludeCacheFor: ['eo', 'cimode'], // languages to not persist (cookie, localStorage)
      // Set the language cookie to be shared across all fs.org subdomains, the
      // same way we share the session cookie across all subdomains.
      cookieDomain,
    },
    ns: ['translation', 'common-ui'],
    postProcess: ['pseudo'],
    backend: {
      backends: [
        // resourcesToBackend({ en: { translation: enAppTranslations, 'common-ui': enCommonTranslations } }),
        resourcesToBackend((language, namespace, callback) => {
          import(
            /* webpackChunkName: "locales-[request]-[index]" */ `/coalesced-locales/dist/${language}/${namespace}.json`
          )
            .then(({ default: resources }) => {
              callback(null, resources)
            })
            .catch((error) => {
              callback(error, null)
            })
        }),
      ],
    },
    partialBundledLanguages: true,
    resources: { en: { translation: enAppTranslations, 'common-ui': enCommonTranslations } },
    // resources: typeof jest === 'undefined' ? undefined : {},
    returnEmptyString: false, // i18next-scanner sometimes generates empty strings
    keySeparator: false, // keeps dotted key paths flat instead of nested
    debug: log.enabled,
    supportedLngs: locales.concat('eo'),
    react: {
      transSupportBasicHtmlNodes: true, // allow <br/> and simple html elements in translations
      transKeepBasicHtmlNodesFor: ['br', 'strong', 'i'], // don't convert to <1></1> if simple react elements
    },
  })
}

function I18nProvider({ i18nInstance = i18n, children }) {
  return React.createElement(I18nextProvider, { i18n: i18nInstance }, children)
}

function addTranslations(componentTranslations = {}) {
  log(`addTranslations`, componentTranslations, i18n)
  // iterate over every language found
  Object.keys(componentTranslations).forEach((lang) => {
    // iterate over each namespace in each language
    Object.keys(componentTranslations[lang]).forEach((namespace) => {
      logVerbose(`adding translations for ${lang} [${namespace}]`, componentTranslations[lang][namespace])
      i18n.addResources(lang, namespace, componentTranslations[lang][namespace])
    })
  })
  // log('i18n data', i18n.store.data)
}

function calculateActiveLangs(languageFlagList) {
  logVerbose('calculateActiveLangs', languageFlagList)
  return languageFlagList.reduce((acc, entry) => {
    logVerbose('calculateActiveLangs entry', entry)
    if ((entry.experiment && showEx(entry.experiment)) || (entry.flag && getFeatureFlag(entry.flag)?.isOn)) {
      log('calculateActiveLangs adding locale to active list due to experiment or flag', entry.locale)
      acc.push(entry.locale)
    }
    return acc
  }, [])
}

/**
 * Resets the locale arrays to their default states.
 *
 * This function restores the global arrays `essentialLocales`, `extendedLocales`,
 * `allLocales`, and `supportedLocales` to their original values using the
 * corresponding `orig*` arrays. It is useful for reverting any changes made to
 * the locale lists during runtime.
 *
 * @function
 * @returns {void}
 */
function resetLocales() {
  logVerbose('Resetting locales to default')
  essentialLocales.splice(0, essentialLocales.length, ...origEssentialLangs)
  extendedLocales.splice(0, extendedLocales.length, ...origExtendedLocalesLangs)
  allLocales.splice(0, allLocales.length, ...origAllLocalesLangs)
  supportedLocales.splice(0, supportedLocales.length, ...origSupportedLocalesLangs)
}

/**
 * Handles the activation of experimental locales by updating the lists of essential, extended, all, and supported locales.
 *
 * This function calculates the currently active experimental locales based on language flags,
 * determines if any experiments are active, and updates the corresponding locale arrays accordingly.
 * It also logs the changes when experiments are active.
 *
 * @function
 * @returns {void}
 */
function handleExperiments() {
  logVerbose('Handling experiments and updating locales')
  const activeExperimentalLocales = {
    essential: calculateActiveLangs(languageFlags.essential),
    extended: calculateActiveLangs(languageFlags.extended),
    supported: calculateActiveLangs(languageFlags.supported),
  }
  const experimentsAreActive =
    [
      ...activeExperimentalLocales.essential,
      ...activeExperimentalLocales.extended,
      ...activeExperimentalLocales.supported,
    ].length > 0

  if (experimentsAreActive) {
    // add back new experimental locales
    essentialLocales.push(...activeExperimentalLocales.essential)
    // experiments moving from extended to essential need to be removed from extended
    pullAll(extendedLocales, ...activeExperimentalLocales.essential)
    extendedLocales.push(...activeExperimentalLocales.extended)
    allLocales.push(...activeExperimentalLocales.extended, ...activeExperimentalLocales.essential)
    supportedLocales.push(...activeExperimentalLocales.supported)
    log(
      'additionalLang experiments are active, adding experimental locales',
      activeExperimentalLocales,
      essentialLocales,
      extendedLocales,
      allLocales,
      supportedLocales
    )
  }
}

/**
 * This function handles custom locales provided by the app.
 * If allowCustomLocales is true, it registers them in the customLocalesMap and adds them to supportedLocales in lowercase for consistency.
 * Appending to supportedLocales simplifies the logic for other functions that need to check if a locale is supported,
 * like setLocalePreference in this package or localeCodeInPath in router base package
 *
 * @param {string[]} appSpecificLocales
 * @returns the lowercased app specific locales to be used in setAppLocales
 */
function handleCustomLocales(appSpecificLocales) {
  logVerbose('Handling custom locales')
  const lowercasedAppSpecificLocales = appSpecificLocales.map((locale) => locale.toLowerCase())
  for (let i = 0; i < lowercasedAppSpecificLocales.length; i++) {
    if (!supportedLocales.includes(lowercasedAppSpecificLocales[i])) {
      // lookup the canonical form of the lowercased locale
      const canonicalLocale = appSpecificLocales[i]
      // register canonical format to localeCanonicalMap with its lowercase variant
      localeCanonicalMap.set(lowercasedAppSpecificLocales[i], canonicalLocale)
      // add lowercase variant to supportedLocales so it can be recognized as supported in functions like setLocalePreference
      supportedLocales.push(lowercasedAppSpecificLocales[i])
    }
  }
  // if we don't return the lowercase version, intersection will ignore custom locales
  return lowercasedAppSpecificLocales
}

function validateAppConfig(locales, config) {
  if (locales.length === 0 && config?.onlyAppSpecific) {
    throw new Error(
      'No locales provided in setAppLocales, but onlyAppSpecific option is true. Please provide at least one locale or remove the onlyAppSpecific option.'
    )
  }

  if (locales.length > 0 && (config?.allowCustomLocales || config?.onlyAppSpecific)) {
    const invalidLocales = locales.filter((locale) => !customLocaleRegex.test(locale))
    if (invalidLocales.length > 0) {
      throw new Error(
        `The following locales are in an invalid format. Locales must be in valid BCP 47 format (e.g. "en", "es", "en-US", "tl-PH"): ${invalidLocales.join(', ')}`
      )
    }
  }
}

/**
 * Sets the application's active locales based on the provided list and options.
 * Handles custom locales, removes duplicates, and updates the i18n instance if necessary.
 *
 * @param {string[]} [appSpecificLocales=[]] - An array of locale strings to be added to the application.
 * @param {Object} [options={}] - Optional configuration object.
 * @param {boolean} [options.allowCustomLocales=false] - If true, allows custom locales to be supported if they are in valid BCP 47 format.
 * @param {boolean} [options.onlyAppSpecific=false] - If true, only app-specific locales will be used, excluding base locales.
 *
 * @example
 * // Basic usage with officially supported locales
 * setAppLocales(['ar'])
 *
 * @example
 * // Custom locales, only BCP 47 format is accepted, and they will be normalized to lowercase
 * // Casing is important for custom locales as it is used to determine the canonical locale for url and cookie updates in setLocalePreference.
 * setAppLocales(['tl-PH'], { allowCustomLocales: true })
 *
 * @example
 * // Using only app-specific locales, excluding base locales
 * setAppLocales(['es', 'fr'], { onlyAppSpecific: true })
 *
 */
export function setAppLocales(appSpecificLocales = [], options = {}) {
  logVerbose('setAppLocales called', appSpecificLocales.length, appLocales.length)

  const { onlyAppSpecific = false, allowCustomLocales = false } = options

  validateAppConfig(appSpecificLocales, options)
  resetLocales()
  handleExperiments()

  let appSpecificLanguages = onlyAppSpecific ? [] : baseLocales
  if (allowCustomLocales) {
    appSpecificLanguages = appSpecificLanguages.concat(handleCustomLocales(appSpecificLocales))
  } else {
    appSpecificLanguages = appSpecificLanguages.concat(appSpecificLocales)
  }

  logVerbose('Removing duplicates')

  removeDuplicates(essentialLocales)
  removeDuplicates(extendedLocales)
  removeDuplicates(allLocales)
  removeDuplicates(supportedLocales)

  logVerbose('setAppLocales b4 combinedLocales', supportedLocales, baseLocales, appSpecificLocales)

  const combinedLocales = intersection(supportedLocales, appSpecificLanguages)
  logVerbose('setAppLocales combinedLocales', combinedLocales, appLocales)

  if (onlyAppSpecific && combinedLocales.length === 0) {
    throw new Error(
      'No locales available after combining appSpecificLocales with supportedLocales. If you are using the onlyAppSpecific option, please ensure that at least one of the provided locales is included in supportedLocales or that allowCustomLocales is set to true with valid custom locales.'
    )
  }

  if (!isEqual(appLocales, combinedLocales)) {
    appLocales = combinedLocales
    _initializeI18nInstance(i18n, appLocales)
  }
}

const jan2000 = new Date(2000, 0)

export function daysOfMonth(date) {
  return range(1, getDaysInMonth(date) + 1).map((dayNum) => format(new Date(2000, 0, dayNum), 'd'))
}

export function daysOfWeek() {
  return range(2, 9).map((dayNum) => format(new Date(2000, 0, dayNum), 'cccc'))
}

function resolver() {
  return i18n.language
}

export const listOfDays = memoize(() => daysOfMonth(jan2000), resolver)
export const listOfDaysInWeek = memoize(() => daysOfWeek(), resolver)

export const listOfMonths = memoize(
  () => range(12).map((monthNum) => format(new Date(2000, monthNum, 1), 'MMMM')),
  resolver
)

export function listOfYears(startYear, endYear) {
  const endOfRange = endYear < startYear ? endYear - 1 : endYear + 1
  return range(startYear, endOfRange).map((yearNum) => format(new Date(yearNum, 0, 1), 'yyyy'))
}

/**
 * Updates the `fslanguage` cookie to the provided canonical locale value.
 *
 * If running in a browser on a `familysearch.org` hostname, the cookie is set with the
 * `.familysearch.org` domain so it can be shared across subdomains.
 * The cookie is only written when its current value differs from
 * `newLocale`.
 *
 * @param {string} newLocale - The normalized locale code to store (e.g., `"en"`, `"pt-BR"`).
 * @returns {boolean} `true` if the cookie value was changed; otherwise `false`.
 */
function updateLocaleInCookie(newLocale) {
  let cookieDomain
  if (
    hasWindow &&
    (window.location.hostname.endsWith('.familysearch.org') || window.location.hostname === 'familysearch.org')
  ) {
    cookieDomain = '.familysearch.org'
  }

  const langCookie = Cookies.get('fslanguage')
  let cookieWasUpdated = false

  if (langCookie !== newLocale) {
    Cookies.set('fslanguage', newLocale, { domain: cookieDomain })
    cookieWasUpdated = true
  }

  return cookieWasUpdated
}

/**
 * Updates the locale segment in a URL pathname and triggers a browser navigation
 * when the locale in the path differs from the requested locale.
 *
 * The function checks `url.pathname` against `langCodePathRegex` (expected to expose
 * a `localeCode` named capture group). If a locale segment is found and is different
 * from `newLocale`, it replaces the leading `/{locale}/` segment with `/{newLocale}/`,
 * calls `window.location.assign(url)`, and returns `true`.
 *
 * @param {URL} url - The URL object whose pathname may contain a locale segment.
 * @param {string} newLocale - The locale code to set in the pathname.
 * @returns {boolean} `true` if the pathname was updated and navigation was triggered; otherwise `false`.
 */
function updateLocaleInPathname(url, newLocale) {
  let urlChanged = false
  const langMatch = url.pathname?.match(langCodePathRegex)
  const currentLangInPath = langMatch?.groups?.localeCode
  if (langMatch && currentLangInPath !== newLocale) {
    url.pathname = url.pathname.replace(new RegExp(`^/${currentLangInPath}/`), `/${newLocale}/`)
    window.location.assign(url)
    urlChanged = true
  }
  return urlChanged
}

/**
 * Updates the `lang` query parameter in a URL and redirects the browser if a change is needed.
 *
 * If the current `lang` query parameter exists and differs from `newLocale`,
 * this function updates the parameter, navigates to the updated URL via
 * `window.location.assign`, and reports that the URL was changed.
 *
 * @param {URL} url - The URL object whose `lang` query parameter may be updated.
 * @param {string} newLocale - The locale value to set for the `lang` query parameter.
 * @returns {boolean} `true` if the URL was updated and a redirect was triggered; otherwise `false`.
 */
function updateLocaleInQueryParam(url, newLocale) {
  let urlChanged = false
  const langQueryParam = url.searchParams.get('lang')
  if (langQueryParam && langQueryParam !== newLocale) {
    url.searchParams.set('lang', newLocale)
    window.location.assign(url.href)
    urlChanged = true
  }
  return urlChanged
}

/**
 * Sets the user's locale preference by updating the language cookie and, if necessary,
 * modifying the URL or reloading the page to reflect the new locale.
 *
 * - If the locale is included in supportedLocales, updates the 'fslanguage' cookie.
 * - If running in a browser environment, updates the URL path or query parameter to match the new locale,
 *   or reloads the page if necessary.
 * - If the locale is not supported, logs a message and does nothing.
 *
 * @param {string} newLocale - The new locale code (in lowercase) to set as the user's preference.
 */
export function setLocalePreference(newLocale) {
  if (!supportedLocales.includes(newLocale)) {
    log(`setLocalePreference for ${newLocale} request ignored as locale is not supported`)
    return
  }

  if (!hasWindow) return

  const canonicalLocale = localeCanonicalMap.get(newLocale) || newLocale
  const cookieWasUpdated = updateLocaleInCookie(canonicalLocale)

  if (i18n.language !== newLocale) {
    const url = new URL(window.location.href)
    const urlWasChanged = updateLocaleInPathname(url, canonicalLocale) || updateLocaleInQueryParam(url, canonicalLocale)

    if (!urlWasChanged && cookieWasUpdated) {
      window.location.reload()
    }
  }
}

// We could attempt to leverage i18n.exists with only a fallbackLng prop – but exists uses a different function underneath than t, which does not handle namespaces the same.
// This can leads to behavior that is not as intuitive as we would like. (People have filed multiple issues about this due to confusion)
// Granted, our logic with namespaces should be pretty stable, but this feels safer.
const isTranslationAvailable = (key) => Boolean(i18n.t(key, { defaultValue: ' ', fallbackLng: 'none' }).trim())

