// This file is used to map lowercase codes to canonical locale codes
// for URL parsing and normalization.
// Traditional and simplified chinese are the first two entries, custom locales can be added here as needed.
const localeCanonicalMap = new Map()
localeCanonicalMap.set('zh', 'zh-Hant')
localeCanonicalMap.set('zh-hant', 'zh-Hant')
localeCanonicalMap.set('zh-hans', 'zh-Hans')

/**
 * This is only for testing purposes to reset the localeCanonicalMap in between tests, since it's a module-level variable that persists across tests
 */
// eslint-disable-next-line no-underscore-dangle -- This is a private function just for testing
function _resetLocaleCanonicalMap() {
  localeCanonicalMap.clear()
  localeCanonicalMap.set('zh', 'zh-Hant')
  localeCanonicalMap.set('zh-hant', 'zh-Hant')
  localeCanonicalMap.set('zh-hans', 'zh-Hans')
}

export { localeCanonicalMap, _resetLocaleCanonicalMap }
